import React, { useEffect, useState } from 'react';
import axios from 'axios';
import {
  Container,
  TextField,
  MenuItem,
  Button,
  Typography,
  Box,
  Paper
} from '@mui/material';

function App() {
  const [clinics, setClinics] = useState([]);

  const [form, setForm] = useState({
    clinic_id: '',
    city: '',
    state: '',
    region: '',
    patient_name: '',
    patient_phone: '',
    channel: '',
    service_type: '',
    description: '',
    file: null // 🔥 IMPORTANTE
  });

  useEffect(() => {
    axios.get('http://localhost:3001/clinics')
      .then(res => setClinics(res.data))
      .catch(err => console.error(err));
  }, []);

  const handleClinicChange = (id) => {
    const clinic = clinics.find(c => c.id === parseInt(id));

    if (clinic) {
      setForm(prev => ({
        ...prev,
        clinic_id: clinic.id,
        city: clinic.city || '',
        state: clinic.state || '',
        region: clinic.region || ''
      }));
    }
  };

  const handleSubmit = async () => {
    const formData = new FormData();

    Object.keys(form).forEach(key => {
      formData.append(key, form[key]);
    });

    try {
      await axios.post('http://localhost:3001/complaints', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      alert('Salvo com sucesso!');

    } catch (error) {
      console.error(error);
      alert('Erro ao salvar');
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={4} sx={{ p: 4, mt: 5, borderRadius: 3 }}>

        <Typography variant="h5" fontWeight="bold">
          Cadastro de Reclamação
        </Typography>

        <TextField
          select
          label="Clínica"
          fullWidth
          margin="normal"
          value={form.clinic_id}
          onChange={(e) => handleClinicChange(e.target.value)}
        >
          {clinics.map(c => (
            <MenuItem key={c.id} value={c.id}>
              {c.name}
            </MenuItem>
          ))}
        </TextField>

        <TextField label="Cidade" value={form.city} fullWidth disabled margin="normal" />
        <TextField label="Estado" value={form.state} fullWidth disabled margin="normal" />
        <TextField label="Região" value={form.region} fullWidth disabled margin="normal" />

        <TextField
          label="Paciente"
          fullWidth
          margin="normal"
          onChange={(e) => setForm({ ...form, patient_name: e.target.value })}
        />

        <TextField
          label="Telefone"
          fullWidth
          margin="normal"
          onChange={(e) => setForm({ ...form, patient_phone: e.target.value })}
        />

        <TextField
          select
          label="Canal"
          fullWidth
          margin="normal"
          onChange={(e) => setForm({ ...form, channel: e.target.value })}
        >
          <MenuItem value="whatsapp">WhatsApp</MenuItem>
          <MenuItem value="email">Email</MenuItem>
          <MenuItem value="google">Google</MenuItem>
          <MenuItem value="facebook">Facebook</MenuItem>
          <MenuItem value="instagram">Instagram</MenuItem>
          <MenuItem value="nps">NPS</MenuItem>
        </TextField>

        <TextField
          select
          label="Serviço"
          fullWidth
          margin="normal"
          onChange={(e) => setForm({ ...form, service_type: e.target.value })}
        >
          <MenuItem value="clinico">Clínico</MenuItem>
          <MenuItem value="ortodontia">Ortodontia</MenuItem>
          <MenuItem value="implante">Implante</MenuItem>
        </TextField>

        <TextField
          label="Descrição"
          multiline
          rows={4}
          fullWidth
          margin="normal"
          onChange={(e) => setForm({ ...form, description: e.target.value })}
        />

        {/* 🔥 AQUI ESTÁ O CAMPO DE UPLOAD */}
        <Box mt={2}>
          <Typography>Anexar evidência</Typography>

          <input
            type="file"
            onChange={(e) =>
              setForm({ ...form, file: e.target.files[0] })
            }
          />
        </Box>

        <Box mt={3}>
          <Button fullWidth variant="contained" onClick={handleSubmit}>
            SALVAR
          </Button>
        </Box>

      </Paper>
    </Container>
  );
}

export default App;
